chrome.runtime.onInstalled.addListener(async()=>{let e=await chrome.tabs.query({url:["http://*/*","https://*/*"]});for(let t of e)t.id!=null&&chrome.scripting.executeScript({target:{tabId:t.id},files:["content.js"]}).catch(()=>{})});chrome.runtime.onMessage.addListener((e,t,a)=>((e.type==="ADD_PET"||e.type==="REMOVE_PET"||e.type==="THROW_BALL"||e.type==="TOGGLE_VISIBILITY")&&chrome.tabs.query({},r=>{for(let s of r)s.id!=null&&chrome.tabs.sendMessage(s.id,e).catch(()=>{})}),!1));
